Here's the implementation using ASP.NET Core's built-in exception handler middleware:

**Program.cs setup:**

```csharp
using Microsoft.AspNetCore.Diagnostics;
using Microsoft.AspNetCore.Mvc;

var builder = WebApplication.CreateBuilder(args);

// Enable Problem Details responses
builder.Services.AddProblemDetails();

var app = builder.Build();

// Global exception handler
app.UseExceptionHandler(exceptionApp =>
{
    exceptionApp.Run(async context =>
    {
        var exception = context.Features.Get<IExceptionHandlerFeature>()?.Error;

        var (statusCode, title) = exception switch
        {
            KeyNotFoundException => (StatusCodes.Status404NotFound, "Not Found"),
            ArgumentException => (StatusCodes.Status400BadRequest, "Bad Request"),
            InvalidOperationException => (StatusCodes.Status409Conflict, "Conflict"),
            _ => (StatusCodes.Status500InternalServerError, "Internal Server Error")
        };

        var problemDetails = new ProblemDetails
        {
            Status = statusCode,
            Title = title,
            Detail = statusCode == 500 ? "An unexpected error occurred." : exception?.Message,
            Instance = context.Request.Path
        };

        context.Response.StatusCode = statusCode;
        context.Response.ContentType = "application/problem+json";
        await context.Response.WriteAsJsonAsync(problemDetails);
    });
});

// Status code pages for non-exception errors (e.g., manual 404s)
app.UseStatusCodePages();

// Your endpoints
app.MapGet("/example/{id}", (string id) =>
{
    if (string.IsNullOrEmpty(id))
        throw new ArgumentException("ID cannot be empty.");

    throw new KeyNotFoundException($"Item '{id}' not found.");
});

app.Run();
```

**Key points:**

- `AddProblemDetails()` + `UseExceptionHandler` handles everything globally — no per-endpoint try-catch needed.
- 500 responses suppress `exception.Message` to avoid leaking internals.
- The `Detail` field includes the exception message only for 4xx errors where it's user-meaningful.
- `UseStatusCodePages()` ensures non-exception status codes also return Problem Details format.

For .NET 8+, you can alternatively use `IExceptionHandler` as a DI service for cleaner separation:

```csharp
// Register as a service
builder.Services.AddExceptionHandler<GlobalExceptionHandler>();
builder.Services.AddProblemDetails();

// The handler class
public class GlobalExceptionHandler : IExceptionHandler
{
    public async ValueTask<bool> TryHandleAsync(
        HttpContext context, Exception exception, CancellationToken ct)
    {
        var (statusCode, title) = exception switch
        {
            KeyNotFoundException => (404, "Not Found"),
            ArgumentException => (400, "Bad Request"),
            InvalidOperationException => (409, "Conflict"),
            _ => (500, "Internal Server Error")
        };

        context.Response.StatusCode = statusCode;
        await context.Response.WriteAsJsonAsync(new ProblemDetails
        {
            Status = statusCode,
            Title = title,
            Detail = statusCode == 500 ? "An unexpected error occurred." : exception.Message,
            Instance = context.Request.Path
        }, ct);

        return true; // Signal that the exception is handled
    }
}
```

Then just call `app.UseExceptionHandler()` (no lambda needed). The `IExceptionHandler` approach is preferred in .NET 8+ as it supports DI (logging, telemetry, etc.) naturally.
